// Sistema de facturación — v0.2.0 (refactored)

const IVA_RATE = 0.19;
const DISCOUNT_HIGH_THRESHOLD = 1000;
const DISCOUNT_HIGH_RATE = 0.15;
const DISCOUNT_MED_THRESHOLD = 500;
const DISCOUNT_MED_RATE = 0.08;

function calcTotal(items) {
  let total = 0;
  for (let i = 0; i < items.length; i++) {
    total = total + items[i].price * items[i].qty;
  }
  return total;
}

function calcDiscount(total) {
  if (total > DISCOUNT_HIGH_THRESHOLD) {
    return total * DISCOUNT_HIGH_RATE;
  }
  if (total > DISCOUNT_MED_THRESHOLD) {
    return total * DISCOUNT_MED_RATE;
  }
  return 0;
}

function calcTax(total) {
  return total * IVA_RATE;
}

function formatSummary(total, tax, discount, customerId) {
  let s = '';
  s = s + 'Cliente: ' + customerId + '\\n';
  s = s + 'Subtotal: $' + (total - tax).toFixed(2) + '\\n';
  s = s + 'IVA (19%): $' + tax.toFixed(2) + '\\n';
  s = s + 'Total: $' + total.toFixed(2) + '\\n';
  if (discount > 0) {
    s = s + 'Descuento aplicado: $' + discount.toFixed(2) + '\\n';
  }
  return s;
}

function processOrder(items, customerId) {
  const total = calcTotal(items);
  const discount = calcDiscount(total);
  const subtotal = total - discount;
  const tax = calcTax(subtotal);
  const finalTotal = subtotal + tax;
  const summary = formatSummary(finalTotal, tax, discount, customerId);
  return { total: finalTotal, summary, tax, discount };
}

