const items = [{ price: 100, qty: 2 }];
const result = processOrder(items, 'CLI-001');
const expected = 200 * 1.19;
if (Math.abs(result.total - expected) > 0.01)
  throw new Error(`Esperado ${expected}, recibido ${result.total}`);

const items = [{ price: 600, qty: 2 }];
const result = processOrder(items, 'CLI-002');
if (result.discount <= 0)
  throw new Error('Debería haber descuento para pedidos >$1000');

const items = [{ price: 50, qty: 1 }];
const result = processOrder(items, 'CLI-XYZ');
if (!result.summary.includes('CLI-XYZ'))
  throw new Error('El resumen debe incluir el ID del cliente');
